#include &lt;stdio.h&gt;
#include &lt;stddef.h&gt;

// NAIVE: Size = 24 bytes (on 64-bit)
struct Naive {
    char a;      // 1 byte + 7 bytes padding
    double b;    // 8 bytes
    char c;      // 1 byte + 7 bytes trailing padding
};

// OPTIMIZED: Size = 16 bytes (on 64-bit)
// Order from largest alignment requirement to smallest
struct Optimized {
    double b;    // 8 bytes
    char a;      // 1 byte
    char c;      // 1 byte + 6 bytes trailing padding
};

int main() {
    printf("Naive Size: %zu\n", sizeof(struct Naive));
    printf("Optimized Size: %zu\n", sizeof(struct Optimized));

    // offsetof lets us physically see the gap
    printf("Offset of Naive.b: %zu\n", offsetof(struct Naive, b)); // 8
    return 0;
}

