// For strictly-defined network protocols, we CANNOT tolerate compiler padding.
// The packed attribute forces the struct to be EXACTLY 9 bytes.
struct __attribute__((packed)) NetworkHeader {
    uint8_t version;    // 1 byte
    uint64_t payload_id; // 8 bytes (Starts at unaligned offset 1!)
};

// CAUTION: Accessing payload_id directly may cause a hardware SIGBUS fault 
