#include &lt;stdio.h&gt;

// We must wrap the union in a struct with an enum to enforce state safety
typedef enum { TYPE_INT, TYPE_FLOAT } ValueType;

typedef struct {
    ValueType type; // The "Tag" tracks what is safely readable
    union {
        int i;
        float f;
    } data;
} Variant;

void print_variant(Variant *v) {
    if (v->type == TYPE_INT) {
        printf("Int: %d\n", v->data.i);
    } else if (v->type == TYPE_FLOAT) {
        printf("Float: %f\n", v->data.f);
    }
}

int main() {
    Variant var = { .type = TYPE_INT, .data.i = 42 };
    print_variant(&var);
    return 0;
}

