// A highly aggressive technique to inspect the raw IEEE 754 bits of a float.
// Using pointers violates Strict Aliasing. Using a Union is completely legal in C99.
uint32_t extract_float_bits(float input) {
    union {
        float f;
        uint32_t i;
    } converter;

    // Write as float, read as int.
    converter.f = input;
    return converter.i;
}

int main() {
    uint32_t raw_bits = extract_float_bits(-1.0f);
    printf("Raw Float Bits: 0x%08X\n", raw_bits);
    return 0;
}

