#include &lt;arpa/inet.h&gt; // Provides htonl, htons

struct NetworkPacket {
    uint32_t session_id;
    uint16_t port;
};

void prepare_packet(struct NetworkPacket *pkt) {
    // Host logic evaluates natively
    uint32_t session = 0x1A2B3C4D;
    uint16_t target_port = 443;

    // Serialize at the EXACT moment before transmission.
    // Once swapped, the data is mathematically useless to the Host CPU math.
    pkt->session_id = htonl(session);
    pkt->port = htons(target_port);

    printf("Host Session: 0x%08X\n", session);
    printf("Net Session:  0x%08X\n", pkt->session_id);
}

#include &lt;stdint.h&gt;

// To safely read a 32-bit integer from a raw byte buffer regardless 
// of host Endianness or hardware padding/alignment faults:
uint32_t parse_network_int(const uint8_t *buffer) {
    // Network is Big-Endian: MSB is at buffer[0].
    // Bitwise shifts execute inside CPU registers natively, bypassing RAM Endianness entirely.
    return ((uint32_t)buffer[0] << 24) |
           ((uint32_t)buffer[1] << 16) |
           ((uint32_t)buffer[2] << 8)  |
           ((uint32_t)buffer[3]);
}

#include &lt;stdint.h&gt;

// An IPv4 Header simplified format.
// Engineer attempts to map struct directly onto incoming packet buffer.
struct __attribute__((packed)) IPHeader {
    uint8_t version : 4;  // 4 bits
    uint8_t ihl : 4;      // 4 bits (Internet Header Length)
    uint8_t tos;          // 1 byte
    uint16_t total_len;
};

int validate_version(struct IPHeader *hdr) {
    return hdr->version == 4;
}

